#include<bits/stdc++.h> 
using namespace std; 
int main(void){
	string a,f;
	int n,b,c,d,sum,maxx,t=0;
	char x,y;
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a>>b>>c>>x>>y>>d;
		sum=0;
		if(b>80&&d>0)sum+=8000;
		if(b>85&&c>80)sum+=4000;
		if(b>90)sum+=2000;
		if(b>85&&y=='Y')sum+=1000;
		if(c>80&&x=='Y')sum+=850;
		t+=sum;
		if(sum>maxx) {
			maxx=sum;
			f=a;
		}
	}
	cout<<f<<endl<<maxx<<endl<<t;
    return 0;
}
